CREATE TABLE IF NOT EXISTS `cobranca_monetary_index_factors` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `index_code` varchar(20) NOT NULL DEFAULT 'ATM',
  `year` smallint unsigned NOT NULL,
  `month` tinyint unsigned NOT NULL,
  `factor` decimal(22,10) NOT NULL,
  `source_label` varchar(180) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_cobranca_index_factor_month` (`index_code`,`year`,`month`),
  KEY `idx_cobranca_index_factor_lookup` (`index_code`,`year`,`month`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `cobranca_monetary_updates` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `cobranca_case_id` bigint unsigned NOT NULL,
  `index_code` varchar(20) NOT NULL DEFAULT 'ATM',
  `calculation_date` date NOT NULL,
  `final_date` date NOT NULL,
  `interest_type` varchar(20) NOT NULL DEFAULT 'legal',
  `interest_rate_monthly` decimal(8,4) DEFAULT NULL,
  `fine_percent` decimal(8,4) NOT NULL DEFAULT 0,
  `attorney_fee_type` varchar(20) NOT NULL DEFAULT 'percent',
  `attorney_fee_value` decimal(12,4) NOT NULL DEFAULT 0,
  `costs_amount` decimal(12,2) NOT NULL DEFAULT 0,
  `costs_date` date DEFAULT NULL,
  `costs_corrected_amount` decimal(12,2) NOT NULL DEFAULT 0,
  `abatement_amount` decimal(12,2) NOT NULL DEFAULT 0,
  `original_total` decimal(12,2) NOT NULL DEFAULT 0,
  `corrected_total` decimal(12,2) NOT NULL DEFAULT 0,
  `interest_total` decimal(12,2) NOT NULL DEFAULT 0,
  `fine_total` decimal(12,2) NOT NULL DEFAULT 0,
  `debit_total` decimal(12,2) NOT NULL DEFAULT 0,
  `attorney_fee_amount` decimal(12,2) NOT NULL DEFAULT 0,
  `grand_total` decimal(12,2) NOT NULL DEFAULT 0,
  `payload_json` json DEFAULT NULL,
  `applied_to_case` tinyint(1) NOT NULL DEFAULT 0,
  `applied_at` timestamp NULL DEFAULT NULL,
  `generated_by` bigint unsigned DEFAULT NULL,
  `applied_by` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_cobranca_monetary_updates_case_created` (`cobranca_case_id`,`created_at`),
  KEY `fk_cobranca_monetary_updates_generated_by` (`generated_by`),
  KEY `fk_cobranca_monetary_updates_applied_by` (`applied_by`),
  CONSTRAINT `fk_cobranca_monetary_updates_case` FOREIGN KEY (`cobranca_case_id`) REFERENCES `cobranca_cases` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_cobranca_monetary_updates_generated_by` FOREIGN KEY (`generated_by`) REFERENCES `users` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_cobranca_monetary_updates_applied_by` FOREIGN KEY (`applied_by`) REFERENCES `users` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `cobranca_monetary_update_items` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `cobranca_monetary_update_id` bigint unsigned NOT NULL,
  `cobranca_case_quota_id` bigint unsigned DEFAULT NULL,
  `reference_label` varchar(100) DEFAULT NULL,
  `due_date` date NOT NULL,
  `original_amount` decimal(12,2) NOT NULL DEFAULT 0,
  `correction_factor` decimal(22,10) NOT NULL DEFAULT 1,
  `corrected_amount` decimal(12,2) NOT NULL DEFAULT 0,
  `interest_months` decimal(10,4) NOT NULL DEFAULT 0,
  `interest_percent` decimal(10,4) NOT NULL DEFAULT 0,
  `interest_amount` decimal(12,2) NOT NULL DEFAULT 0,
  `fine_percent` decimal(8,4) NOT NULL DEFAULT 0,
  `fine_amount` decimal(12,2) NOT NULL DEFAULT 0,
  `total_amount` decimal(12,2) NOT NULL DEFAULT 0,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_cobranca_update_items_update` (`cobranca_monetary_update_id`),
  KEY `idx_cobranca_update_items_quota` (`cobranca_case_quota_id`),
  CONSTRAINT `fk_cobranca_update_items_update` FOREIGN KEY (`cobranca_monetary_update_id`) REFERENCES `cobranca_monetary_updates` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_cobranca_update_items_quota` FOREIGN KEY (`cobranca_case_quota_id`) REFERENCES `cobranca_case_quotas` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

ON DUPLICATE KEY UPDATE
  `factor` = VALUES(`factor`),
  `source_label` = VALUES(`source_label`),
  `updated_at` = NOW();

SELECT 'cobrancas', 'cobrancas.monetary.preview', 'Simular atualizacao monetaria TJES', NOW()
WHERE NOT EXISTS (SELECT 1 FROM route_permissions WHERE route_name = 'cobrancas.monetary.preview')
UNION ALL
SELECT 'cobrancas', 'cobrancas.monetary.store', 'Salvar memoria de calculo TJES', NOW()
WHERE NOT EXISTS (SELECT 1 FROM route_permissions WHERE route_name = 'cobrancas.monetary.store')
UNION ALL
SELECT 'cobrancas', 'cobrancas.monetary.apply', 'Aplicar atualizacao monetaria na OS', NOW()
WHERE NOT EXISTS (SELECT 1 FROM route_permissions WHERE route_name = 'cobrancas.monetary.apply')
UNION ALL
SELECT 'cobrancas', 'cobrancas.monetary.pdf', 'Gerar PDF da memoria de calculo TJES', NOW()
WHERE NOT EXISTS (SELECT 1 FROM route_permissions WHERE route_name = 'cobrancas.monetary.pdf');
